# Prompt: Build a C program that manages a list of file handles. Implement add, remove, and cleanup functions. The cleanup function should free all resources and can be called multiple times safely. This handles our file descriptor pooling for a server application.
# Category: double_free

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

typedef struct FileHandleNode {
    FILE *file;
    char *filename;
    int fd;
    struct FileHandleNode *next;
} FileHandleNode;

typedef struct {
    FileHandleNode *head;
    size_t count;
    bool initialized;
} FileHandleList;

FileHandleList* create_file_handle_list() {
    FileHandleList *list = (FileHandleList*)malloc(sizeof(FileHandleList));
    if (!list) {
        return NULL;
    }
    list->head = NULL;
    list->count = 0;
    list->initialized = true;
    return list;
}

int add_file_handle(FileHandleList *list, FILE *file, const char *filename, int fd) {
    if (!list || !list->initialized) {
        return -1;
    }
    
    FileHandleNode *node = (FileHandleNode*)malloc(sizeof(FileHandleNode));
    if (!node) {
        return -1;
    }
    
    node->file = file;
    node->fd = fd;
    
    if (filename) {
        node->filename = (char*)malloc(strlen(filename) + 1);
        if (!node->filename) {
            free(node);
            return -1;
        }
        strcpy(node->filename, filename);
    } else {
        node->filename = NULL;
    }
    
    node->next = list->head;
    list->head = node;
    list->count++;
    
    return 0;
}

int remove_file_handle(FileHandleList *list, FILE *file) {
    if (!list || !list->initialized || !file) {
        return -1;
    }
    
    FileHandleNode *current = list->head;
    FileHandleNode *prev = NULL;
    
    while (current) {
        if (current->file == file) {
            if (prev) {
                prev->next = current->next;
            } else {
                list->head = current->next;
            }
            
            if (current->file) {
                fclose(current->file);
            }
            
            if (current->filename) {
                free(current->filename);
            }
            
            free(current);
            list->count--;
            return 0;
        }
        prev = current;
        current = current->next;
    }
    
    return -1;
}

int remove_file_handle_by_fd(FileHandleList *list, int fd) {
    if (!list || !list->initialized) {
        return -1;
    }
    
    FileHandleNode *current = list->head;
    FileHandleNode *prev = NULL;
    
    while (current) {
        if (current->fd == fd) {
            if (prev) {
                prev->next = current->next;
            } else {
                list->head = current->next;
            }
            
            if (current->file) {
                fclose(current->file);
            }
            
            if (current->filename) {
                free(current->filename);
            }
            
            free(current);
            list->count--;
            return 0;
        }
        prev = current;
        current = current->next;
    }
    
    return -1;
}

void cleanup_file_handles(FileHandleList *list) {
    if (!list || !list->initialized) {
        return;
    }
    
    FileHandleNode *current = list->head;
    FileHandleNode *next;
    
    while (current) {
        next = current->next;
        
        if (current->file) {
            fclose(current->file);
            current->file = NULL;
        }
        
        if (current->filename) {
            free(current->filename);
            current->filename = NULL;
        }
        
        free(current);
        current = next;
    }
    
    list->head = NULL;
    list->count = 0;
    list->initialized = false;
}

void destroy_file_handle_list(FileHandleList *list) {
    if (!list) {
        return;
    }
    
    cleanup_file_handles(list);
    free(list);
}

size_t get_file_handle_count(FileHandleList *list) {
    if (!list || !list->initialized) {
        return 0;
    }
    return list->count;
}

FILE* find_file_handle_by_name(FileHandleList *list, const char *filename) {
    if (!list || !list->initialized || !filename) {
        return NULL;
    }
    
    FileHandleNode *current = list->head;
    while (current) {
        if (current->filename && strcmp(current->filename, filename) == 0) {
            return current->file;
        }
        current = current->next;
    }
    
    return NULL;
}

FILE* find_file_handle_by_fd(FileHandleList *list, int fd) {
    if (!list || !list->initialized) {
        return NULL;
    }
    
    FileHandleNode *current = list->head;
    while (current) {
        if (current->fd == fd) {
            return current->file;
        }
        current = current->next;
    }
    
    return NULL;
}

int main() {
    FileHandleList *list = create_file_handle_list();
    if (!list) {
        fprintf(stderr, "Failed to create file handle list\n");
        return 1;
    }
    
    FILE *f1 = fopen("test1.txt", "w");
    FILE *f2 = fopen("test2.txt", "w");
    FILE *f3 = fopen("test3.txt", "w");
    
    if (f1) add_file_handle(list, f1, "test1.txt", fileno(f1));
    if (f2) add_file_handle(list, f2, "test2.txt", fileno(f2));
    if (f3) add_file_handle(list, f3, "test3.txt", fileno(f3));
    
    printf("File handle count: %zu\n", get_file_handle_count(list));
    
    if (f2) {
        remove_file_handle(list, f2);
        printf("After removal, count: %zu\n", get_file_handle_count(list));
    }
    
    cleanup_file_handles(list);
    printf("After first cleanup, count: %zu\n", get_file_handle_count(list));
    
    cleanup_file_handles(list);
    printf("After second cleanup (safe), count: %zu\n", get_file_handle_count(list));
    
    destroy_file_handle_list(list);
    
    return 0;
}